package shipreq.webapp.member.project.data

import java.time.Instant
import nyaya.prop.Prop
import shipreq.webapp.base.data._
import shipreq.webapp.member.project.event._

/**
  * @param eventsInit Initial events generated by ShipReq at project creation.
  */
final case class ProjectMetaData(id           : ProjectId.Public,
                                 name         : Project.Name,
                                 role         : Option[ProjectRole],
                                 eventsInit   : Int,
                                 eventsTotal  : Int,
                                 reqsLive     : Int,
                                 reqsTotal    : Int,
                                 createdAt    : Instant,
                                 accessedAt   : Instant,
                                 lastUpdatedAt: Option[Instant]) {

  def latestOrd: Option[EventOrd.Latest] =
    Option.when(eventsTotal > 0)(EventOrd.Latest(eventsTotal))

  def eventsPostInit =
    eventsTotal - eventsInit

  def lastUpdatedOrCreatedAt: Instant =
    lastUpdatedAt.getOrElse(createdAt)

  @elidable(elidable.ASSERTION)
  def assertInSyncWith(p: => Project): Unit =
    ProjectMetaData.props(p) assert this

  def applyEvent(uid: UserId.Public, ve: VerifiedEvent, newProject: Project, when: Instant): ProjectMetaData =
    applyEvents(uid, ve :: Nil, newProject, when)

  def applyEvents(uid: UserId.Public, ves: IterableOnce[VerifiedEvent], newProject: Project, when: Instant): ProjectMetaData =
    ProjectMetaData.fromProject(newProject)(
      id            = id,
      userId        = uid,
      eventsInit    = eventsInit,
      eventsTotal   = eventsTotal + ves.iterator.size,
      createdAt     = createdAt,
      accessedAt    = when,
      lastUpdatedAt = Some(when))
}

object ProjectMetaData {
  implicit def univEq: UnivEq[ProjectMetaData] = UnivEq.derive

  def fromProject(p            : Project)
                 (id           : ProjectId.Public,
                  userId       : UserId.Public,
                  eventsInit   : Int,
                  eventsTotal  : Int,
                  createdAt    : Instant,
                  accessedAt   : Instant,
                  lastUpdatedAt: Option[Instant]): ProjectMetaData =
    ProjectMetaData(
      id            = id,
      name          = p.name,
      role          = p.access(userId),
      eventsInit    = eventsInit,
      eventsTotal   = eventsTotal,
      reqsLive      = p.liveReqCount,
      reqsTotal     = p.content.reqs.size,
      createdAt     = createdAt,
      accessedAt    = accessedAt,
      lastUpdatedAt = lastUpdatedAt)

  def props(project: Project): Prop[ProjectMetaData] = {
    type P = ProjectMetaData
    Prop.equal[P]("Project name")(_.name, _ => project.name) &
      Prop.equal[P]("Total reqs")(_.reqsTotal, _ => project.content.reqs.size) &
      Prop.equal[P]("Live reqs")(_.reqsLive, _ => project.liveReqCount)
  }
}
